const i=new Map,s=new Map;async function $(e,r){const t=`${e}_${r}`;if(i.has(t))return i.get(t);if(s.has(t))return s.get(t);const n=l(e,r,t);s.set(t,n);try{return await n}finally{s.delete(t)}}async function l(e,r,t){try{let n;switch(r){case"ESV":n=await y(e);break;case"NLT":n=await d(e);break;case"KJV":n=await u(e);break;case"WEB":n=h(e);break;default:n=await f(e,r);break}return i.set(t,n),n}catch(n){return console.warn(`Failed to fetch ${e} in ${r}, falling back`,n),k(e,r)}}async function y(e){var n;const r=await fetch(`/api/esv?q=${encodeURIComponent(e)}`);if(!r.ok)throw new Error(`ESV API error: ${r.status}`);const t=await r.json();return((n=t.passages)==null?void 0:n[0])||t.text||""}async function d(e){const r=await fetch(`/api/nlt?q=${encodeURIComponent(e)}`);if(!r.ok)throw new Error(`NLT API error: ${r.status}`);const t=await r.json();return t.text||t.passage||""}async function f(e,r){var a;const t=await fetch(`/api/bolls?q=${encodeURIComponent(e)}&v=${encodeURIComponent(r)}`);if(!t.ok)throw new Error(`Bolls API error: ${t.status}`);const n=await t.json();return(a=n.passages)!=null&&a[0]?n.passages[0]:Array.isArray(n)?n.map(c=>c.text).join(" "):n.text||""}async function u(e){const r=e.match(/^(.+?)\s+(\d+)$/);if(!r)return"";const[,t,n]=r,a=t.toLowerCase().replace(/\s+/g,"-");try{const c=await fetch(`/bible/kjv/${a}/${n}.json`);if(c.ok){const o=await c.json();return Array.isArray(o)?o.map(w=>w.text).join(" "):o.text||JSON.stringify(o)}}catch{}return f(e,"KJV")}function h(e){return"World English Bible text — loading..."}async function k(e,r){if(r!=="KJV")try{const t=await u(e);if(t)return i.set(`${e}_KJV`,t),t}catch{}return h()}export{$ as f};
